window.I18N = {"en":{"nav.features":"Features","nav.maps":"Map apps","nav.how":"How it works","nav.setup":"How to use","hero.badge":"Android · Mock GPS · MIT","hero.tagline":"Android mock-GPS route player — drive a scripted route at a set speed to test location-based apps.","hero.cta":"View on GitHub","hero.cta2":"How to use","hero.download":"Download APK","hero.shot_alt":"Route Spoofer main screen with a multi-point route on the map","what.heading":"What it is","what.body":"Route Spoofer is a standalone Android app that injects a scripted, moving GPS location into your whole device. You draw a route, set a speed and press Play — and every other app on the phone reads the simulated position as if you were really there. No root, no separate desktop tool: it runs entirely on the phone.","who.heading":"Who it's for","who.intro":"Built for QA engineers and developers who work on location-based apps — driver, navigation, delivery and dispatch products.","who.items.0.title":"Test without moving","who.items.0.text":"Exercise a driver, navigation, delivery or dispatch app from your desk instead of walking or driving a real route.","who.items.1.title":"Reproducible playback","who.items.1.text":"Replay the exact same route at the exact same speed on every run — ideal for regression tests and bug reproduction.","who.items.2.title":"Believable demos","who.items.2.text":"Show a ride-hailing or dispatch platform with a realistic moving trip, without sending anyone outside.","maps.heading":"Works with any map app","maps.body":"Because the location is injected at the system level, the fake position appears everywhere — not just inside Route Spoofer. Open Google Maps, Yandex Maps, Maps.me or any navigator and watch the marker follow your scripted route.","maps.banner_alt":"Android “Mock location is on” system banner","maps.tiles.0.label":"Google Maps","maps.tiles.0.alt":"Spoofed location shown in Google Maps","maps.tiles.1.label":"Yandex Maps","maps.tiles.1.alt":"Spoofed location shown in Yandex Maps","maps.tiles.2.label":"Maps.me","maps.tiles.2.alt":"Spoofed location shown in Maps.me","maps.tiles.3.label":"2GIS","maps.tiles.3.alt":"Spoofed location shown in 2GIS","features.heading":"Features","features.items.0.title":"Multi-point routes","features.items.0.text":"Tap A → B → C … to draw a route; Route Spoofer interpolates a smooth path between the points.","features.items.1.title":"Speed & interval","features.items.1.text":"Set the playback speed in km/h and how often a location fix is emitted.","features.items.2.title":"Play · Pause · Stop","features.items.2.text":"Start, pause and stop the run at any moment.","features.items.3.title":"Loop modes","features.items.3.text":"Choose loop off, restart from the start, or ping-pong back and forth along the route.","features.items.4.title":"Live telemetry","features.items.4.text":"A HUD shows speed, heading, progress and distance, with a running log of emitted fixes.","features.items.5.title":"Saved locally","features.items.5.text":"Your route is stored on the device — reopen the app and replay it.","features.items.6.title":"Foreground service","features.items.6.text":"A native foreground service keeps emitting the location even while the app is in the background.","multilingual.heading":"Multilingual interface","multilingual.body":"The app interface itself is translated into several languages and switches on the fly — handy when you test the same flow across locales.","multilingual.alt_a":"Route Spoofer interface in Chinese","multilingual.alt_b":"Route Spoofer interface in Spanish","how.heading":"How it works","how.body":"A Capacitor 7 web UI built with HTML and JavaScript handles route drawing and preview. A native Kotlin foreground service injects the position into Android's GPS and NETWORK test providers, so the fix reaches the whole system. Route Spoofer must be selected as the system mock-location app. The project is built with the JDK 21 toolchain.","how.chips.0":"Capacitor 7 web UI","how.chips.1":"Kotlin foreground service","how.chips.2":"GPS + NETWORK mock providers","how.chips.3":"JDK 21","setup.heading":"How to use","setup.intro":"A one-time phone setup, then press Play. The two screenshots below show the developer-mode steps.","setup.steps_title":"Phone setup","setup.steps.0.n":"1","setup.steps.0.title":"Enable Developer options","setup.steps.0.text":"Open Settings → About phone → Software information and tap Build number seven times to unlock Developer options.","setup.steps.1.n":"2","setup.steps.1.title":"Install the app","setup.steps.1.text":"Allow installs from unknown sources and sideload the app-debug.apk file onto the phone.","setup.steps.2.n":"3","setup.steps.2.title":"Select mock-location app","setup.steps.2.text":"In Developer options open “Select mock location app” and choose Route Spoofer.","setup.steps.3.n":"4","setup.steps.3.title":"Launch & grant","setup.steps.3.text":"Open Route Spoofer, grant Location and Notifications, wait for the readiness card, then press Play.","setup.shot_a_alt":"Software information screen — tap Build number to enable Developer options","setup.shot_b_alt":"In-app readiness card asking to select Route Spoofer as the mock-location app","setup.build_title":"Get the APK","setup.builds.0.title":"Cloud build","setup.builds.0.text":"GitHub Actions builds the app — download the app-debug.apk artifact from the workflow run.","setup.builds.1.title":"Local build","setup.builds.1.text":"Or build it yourself in Android Studio with JDK 21 and the Android SDK.","platform.heading":"Platform support","platform.body":"Android only. iOS has no public mock-location API, so it cannot be supported.","platform.android":"Android — supported","platform.ios":"iOS — not supported","license.heading":"License","license.body":"Released under the MIT License — © 2026 Maxim Popelnitskiy. Free to use, modify and distribute.","footer.tagline":"Android mock-GPS route player for testing location-based apps.","footer.github":"View on GitHub","footer.license":"MIT License","footer.author":"by Maxim Popelnitskiy","footer.rights":"© 2026 Maxim Popelnitskiy","footer.privacy":"Privacy","footer.cookies":"Cookies","lang_label":"Language","privacy.title":"Privacy Policy — Route Spoofer","privacy.desc":"Privacy policy for the Route Spoofer Android app and website: no accounts, no analytics, no personal data collected.","privacy.heading":"Privacy Policy","privacy.intro":"Route Spoofer is an open-source (MIT) Android app for developers and QA to play a scripted GPS route while testing location-based apps. This policy covers the app and this website.","privacy.app_heading":"The app","privacy.app.0":"No account, no sign-up.","privacy.app.1":"Collects no personal data and sends nothing to any server. No analytics, no advertising, no third-party tracking SDKs.","privacy.app.2":"The Location permission is used only on your device to emit a mock GPS location; your location is never stored remotely or transmitted.","privacy.app.3":"The Notifications permission is used only to show the foreground-service status notification.","privacy.app.4":"The route you draw is stored locally on your device; clear app data or uninstall to remove it.","privacy.web_heading":"This website","privacy.web.0":"A static informational site. No sign-up, no contact forms, no personal data collected.","privacy.web.1":"Your language choice is kept in your browser's localStorage so the site remembers it; it stays on your device and is never sent to us.","privacy.web.2":"The hosting provider keeps standard server request logs (IP address, user agent, timestamp) for security and operation. This site is hosted by GitHub, Inc.","privacy.closing":"We do not sell or share data. As we collect no personal data, there is nothing on our side to access, correct, or delete; on-device data is fully under your control.","privacy.contact_label":"Contact:","privacy.contact_link":"GitHub issues","privacy.updated_label":"Last updated:","privacy.updated":"2026-06-25","cookies.title":"Cookies & Local Storage — Route Spoofer","cookies.desc":"Cookie notice for the Route Spoofer website: no tracking or advertising cookies; one functional language item in localStorage.","cookies.heading":"Cookies & Local Storage","cookies.body.0":"This website uses no tracking, analytics, or advertising cookies, and no third-party cookies.","cookies.body.1":"This site sets no cookies at all.","cookies.body.2":"It keeps one functional item in your browser's localStorage — your selected language (\"route-spoofer.lang\") — so your preferred language is shown on return. It stays on your device, is not sent to us, and you can clear it anytime in your browser settings.","cookies.body.3":"The host keeps standard server logs as described in the Privacy Policy. Because no tracking technologies are used, there is no consent banner.","cookies.updated_label":"Last updated:","cookies.updated":"2026-06-25"},"ru":{"nav.features":"Возможности","nav.maps":"Карты","nav.how":"Как устроено","nav.setup":"Как пользоваться","hero.badge":"Android · Подмена GPS · MIT","hero.tagline":"Проигрыватель маршрутов с подменой GPS для Android — двигайтесь по заданному маршруту с нужной скоростью, чтобы тестировать геолокационные приложения.","hero.cta":"Открыть на GitHub","hero.cta2":"Как пользоваться","hero.download":"Скачать APK","hero.shot_alt":"Главный экран Route Spoofer с маршрутом из нескольких точек на карте","what.heading":"Что это","what.body":"Route Spoofer — отдельное Android-приложение, которое подаёт на всё устройство движущуюся, заранее заданную GPS-координату. Вы рисуете маршрут, задаёте скорость и нажимаете Play — и любое другое приложение на телефоне считывает смоделированную позицию как настоящую. Без root и без отдельной программы на компьютере: всё работает прямо на телефоне.","who.heading":"Для кого","who.intro":"Создан для QA-инженеров и разработчиков геолокационных приложений — для водителей, навигации, доставки и диспетчеризации.","who.items.0.title":"Тест без перемещения","who.items.0.text":"Проверяйте приложение для водителя, навигации, доставки или диспетчеризации прямо за рабочим столом, не проходя и не проезжая реальный маршрут.","who.items.1.title":"Воспроизводимость","who.items.1.text":"Повторяйте один и тот же маршрут с одной и той же скоростью на каждом запуске — идеально для регрессионных тестов и воспроизведения багов.","who.items.2.title":"Убедительные демо","who.items.2.text":"Покажите платформу такси или диспетчеризации с реалистичной движущейся поездкой, никого не отправляя на улицу.","maps.heading":"Работает с любым картографическим приложением","maps.body":"Поскольку координата подаётся на уровне системы, поддельная позиция появляется везде — не только внутри Route Spoofer. Откройте Google Maps, Яндекс Карты, Maps.me или любой навигатор и наблюдайте, как маркер движется по вашему маршруту.","maps.banner_alt":"Системный баннер Android «Используется фиктивное местоположение»","maps.tiles.0.label":"Google Maps","maps.tiles.0.alt":"Подменённое местоположение в Google Maps","maps.tiles.1.label":"Яндекс Карты","maps.tiles.1.alt":"Подменённое местоположение в Яндекс Картах","maps.tiles.2.label":"Maps.me","maps.tiles.2.alt":"Подменённое местоположение в Maps.me","maps.tiles.3.label":"2GIS","maps.tiles.3.alt":"Подменённое местоположение в 2GIS","features.heading":"Возможности","features.items.0.title":"Маршрут из точек","features.items.0.text":"Нажимайте A → B → C …, чтобы нарисовать маршрут; Route Spoofer строит плавный путь между точками.","features.items.1.title":"Скорость и интервал","features.items.1.text":"Задайте скорость воспроизведения в км/ч и частоту отправки координат.","features.items.2.title":"Play · Pause · Stop","features.items.2.text":"Запускайте, ставьте на паузу и останавливайте воспроизведение в любой момент.","features.items.3.title":"Режимы цикла","features.items.3.text":"Выберите: цикл выключен, перезапуск с начала или «туда-обратно» по маршруту.","features.items.4.title":"Живая телеметрия","features.items.4.text":"HUD показывает скорость, курс, прогресс и расстояние, а также журнал отправленных координат.","features.items.5.title":"Сохранение на устройстве","features.items.5.text":"Маршрут хранится на устройстве — откройте приложение снова и воспроизведите его.","features.items.6.title":"Фоновая служба","features.items.6.text":"Нативная фоновая служба продолжает отправлять координаты, даже когда приложение свёрнуто.","multilingual.heading":"Многоязычный интерфейс","multilingual.body":"Интерфейс самого приложения переведён на несколько языков и переключается на лету — удобно, когда вы тестируете один и тот же сценарий на разных локалях.","multilingual.alt_a":"Интерфейс Route Spoofer на китайском языке","multilingual.alt_b":"Интерфейс Route Spoofer на испанском языке","how.heading":"Как устроено","how.body":"Веб-интерфейс на Capacitor 7, написанный на HTML и JavaScript, отвечает за рисование и предпросмотр маршрута. Нативная фоновая служба на Kotlin подаёт позицию в тестовые провайдеры Android GPS и NETWORK, поэтому координата доходит до всей системы. Route Spoofer нужно выбрать системным приложением для фиктивного местоположения. Проект собирается на тулчейне JDK 21.","how.chips.0":"Веб-интерфейс Capacitor 7","how.chips.1":"Фоновая служба на Kotlin","how.chips.2":"Mock-провайдеры GPS + NETWORK","how.chips.3":"JDK 21","setup.heading":"Как пользоваться","setup.intro":"Однократная настройка телефона — и нажимайте Play. Два скриншота ниже показывают шаги в режиме разработчика.","setup.steps_title":"Настройка телефона","setup.steps.0.n":"1","setup.steps.0.title":"Включите режим разработчика","setup.steps.0.text":"Откройте Настройки → О телефоне → Сведения о ПО и нажмите «Номер сборки» семь раз, чтобы открыть параметры разработчика.","setup.steps.1.n":"2","setup.steps.1.title":"Установите приложение","setup.steps.1.text":"Разрешите установку из неизвестных источников и установите файл app-debug.apk на телефон.","setup.steps.2.n":"3","setup.steps.2.title":"Выберите mock-приложение","setup.steps.2.text":"В параметрах разработчика откройте «Приложение для фиктивных местоположений» и выберите Route Spoofer.","setup.steps.3.n":"4","setup.steps.3.title":"Запуск и разрешения","setup.steps.3.text":"Откройте Route Spoofer, выдайте доступ к геолокации и уведомлениям, дождитесь карточки готовности и нажмите Play.","setup.shot_a_alt":"Экран «Сведения о ПО» — нажмите «Номер сборки», чтобы включить режим разработчика","setup.shot_b_alt":"Карточка готовности приложения с просьбой выбрать Route Spoofer приложением для фиктивных местоположений","setup.build_title":"Получить APK","setup.builds.0.title":"Облачная сборка","setup.builds.0.text":"GitHub Actions собирает приложение — скачайте артефакт app-debug.apk из запуска workflow.","setup.builds.1.title":"Локальная сборка","setup.builds.1.text":"Или соберите самостоятельно в Android Studio с JDK 21 и Android SDK.","platform.heading":"Поддержка платформ","platform.body":"Только Android. У iOS нет публичного API для фиктивного местоположения, поэтому он не поддерживается.","platform.android":"Android — поддерживается","platform.ios":"iOS — не поддерживается","license.heading":"Лицензия","license.body":"Распространяется под лицензией MIT — © 2026 Maxim Popelnitskiy. Можно свободно использовать, изменять и распространять.","footer.tagline":"Проигрыватель маршрутов с подменой GPS для Android для тестирования геолокационных приложений.","footer.github":"Открыть на GitHub","footer.license":"Лицензия MIT","footer.author":"Максим Попельницкий","footer.rights":"© 2026 Maxim Popelnitskiy","footer.privacy":"Конфиденциальность","footer.cookies":"Cookies","lang_label":"Язык","privacy.title":"Политика конфиденциальности — Route Spoofer","privacy.desc":"Политика конфиденциальности приложения Route Spoofer для Android и этого сайта: без аккаунтов, без аналитики, без сбора персональных данных.","privacy.heading":"Политика конфиденциальности","privacy.intro":"Route Spoofer — это приложение с открытым исходным кодом (MIT) для Android, позволяющее разработчикам и QA воспроизводить заданный GPS-маршрут при тестировании геолокационных приложений. Эта политика распространяется на приложение и на этот сайт.","privacy.app_heading":"Приложение","privacy.app.0":"Без аккаунта и без регистрации.","privacy.app.1":"Не собирает персональные данные и ничего не отправляет на серверы. Без аналитики, без рекламы, без сторонних трекинговых SDK.","privacy.app.2":"Разрешение на геолокацию используется только на вашем устройстве для подачи фиктивной GPS-координаты; ваше местоположение не хранится удалённо и не передаётся.","privacy.app.3":"Разрешение на уведомления используется только для показа статуса фоновой службы.","privacy.app.4":"Нарисованный вами маршрут хранится локально на устройстве; очистите данные приложения или удалите его, чтобы стереть маршрут.","privacy.web_heading":"Этот сайт","privacy.web.0":"Статический информационный сайт. Без регистрации, без форм обратной связи, без сбора персональных данных.","privacy.web.1":"Ваш выбор языка хранится в localStorage браузера, чтобы сайт его запомнил; он остаётся на вашем устройстве и никогда нам не передаётся.","privacy.web.2":"Хостинг-провайдер ведёт стандартные журналы запросов сервера (IP-адрес, user agent, отметка времени) для безопасности и работы. Этот сайт размещён на GitHub, Inc.","privacy.closing":"Мы не продаём и не передаём данные. Поскольку мы не собираем персональных данных, у нас нечего предоставлять, исправлять или удалять; данные на устройстве полностью под вашим контролем.","privacy.contact_label":"Контакт:","privacy.contact_link":"GitHub issues","privacy.updated_label":"Обновлено:","privacy.updated":"2026-06-25","cookies.title":"Cookies и локальное хранилище — Route Spoofer","cookies.desc":"Уведомление о cookies на сайте Route Spoofer: без трекинговых и рекламных cookies; один функциональный элемент языка в localStorage.","cookies.heading":"Cookies и локальное хранилище","cookies.body.0":"Этот сайт не использует трекинговые, аналитические или рекламные cookies, а также сторонние cookies.","cookies.body.1":"Этот сайт вообще не устанавливает cookies.","cookies.body.2":"Он хранит один функциональный элемент в localStorage браузера — выбранный вами язык («route-spoofer.lang»), — чтобы при возвращении показывать предпочитаемый язык. Он остаётся на вашем устройстве, не передаётся нам, и вы можете очистить его в любой момент в настройках браузера.","cookies.body.3":"Хостинг ведёт стандартные журналы сервера, как описано в Политике конфиденциальности. Поскольку технологии отслеживания не используются, баннера согласия нет.","cookies.updated_label":"Обновлено:","cookies.updated":"2026-06-25"},"de":{"nav.features":"Funktionen","nav.maps":"Karten-Apps","nav.how":"So funktioniert’s","nav.setup":"Anleitung","hero.badge":"Android · Mock-GPS · MIT","hero.tagline":"Android-Routenplayer mit Mock-GPS — fahre eine vorgegebene Route mit eingestelltem Tempo ab, um standortbasierte Apps zu testen.","hero.cta":"Auf GitHub ansehen","hero.cta2":"Anleitung","hero.download":"APK herunterladen","hero.shot_alt":"Route-Spoofer-Hauptbildschirm mit einer mehrstufigen Route auf der Karte","what.heading":"Was es ist","what.body":"Route Spoofer ist eine eigenständige Android-App, die eine vorgegebene, sich bewegende GPS-Position an das gesamte Gerät liefert. Du zeichnest eine Route, stellst ein Tempo ein und drückst auf Play — und jede andere App auf dem Telefon liest die simulierte Position, als wärst du wirklich dort. Kein Root, kein separates Desktop-Tool: Alles läuft direkt auf dem Telefon.","who.heading":"Für wen","who.intro":"Gemacht für QA-Ingenieure und Entwickler, die an standortbasierten Apps arbeiten — Fahrer-, Navigations-, Liefer- und Dispatch-Anwendungen.","who.items.0.title":"Testen ohne Bewegung","who.items.0.text":"Bring eine Fahrer-, Navigations-, Liefer- oder Dispatch-App vom Schreibtisch aus zum Laufen, statt eine echte Route zu Fuß oder mit dem Auto abzufahren.","who.items.1.title":"Reproduzierbare Wiedergabe","who.items.1.text":"Spiele bei jedem Durchlauf exakt dieselbe Route mit exakt demselben Tempo ab — ideal für Regressionstests und das Nachstellen von Fehlern.","who.items.2.title":"Überzeugende Demos","who.items.2.text":"Zeige eine Ride-Hailing- oder Dispatch-Plattform mit einer realistischen, bewegten Fahrt, ohne jemanden nach draußen zu schicken.","maps.heading":"Funktioniert mit jeder Karten-App","maps.body":"Da die Position auf Systemebene eingespeist wird, erscheint die gefälschte Position überall — nicht nur in Route Spoofer. Öffne Google Maps, Yandex Maps, Maps.me oder einen beliebigen Navigator und sieh zu, wie der Marker deiner vorgegebenen Route folgt.","maps.banner_alt":"Android-Systembanner „Mock-Standort ist aktiv“","maps.tiles.0.label":"Google Maps","maps.tiles.0.alt":"Gefälschte Position in Google Maps","maps.tiles.1.label":"Yandex Maps","maps.tiles.1.alt":"Gefälschte Position in Yandex Maps","maps.tiles.2.label":"Maps.me","maps.tiles.2.alt":"Gefälschte Position in Maps.me","maps.tiles.3.label":"2GIS","maps.tiles.3.alt":"Gefälschte Position in 2GIS","features.heading":"Funktionen","features.items.0.title":"Mehrpunkt-Routen","features.items.0.text":"Tippe A → B → C …, um eine Route zu zeichnen; Route Spoofer interpoliert einen weichen Pfad zwischen den Punkten.","features.items.1.title":"Tempo & Intervall","features.items.1.text":"Stelle das Wiedergabetempo in km/h ein und wie oft eine Position gesendet wird.","features.items.2.title":"Wiedergabe · Pause · Stopp","features.items.2.text":"Starte, pausiere und stoppe den Lauf jederzeit.","features.items.3.title":"Schleifenmodi","features.items.3.text":"Wähle Schleife aus, Neustart vom Anfang oder Pingpong hin und her entlang der Route.","features.items.4.title":"Live-Telemetrie","features.items.4.text":"Ein HUD zeigt Tempo, Kurs, Fortschritt und Distanz, mit einem laufenden Protokoll der gesendeten Punkte.","features.items.5.title":"Lokal gespeichert","features.items.5.text":"Deine Route wird auf dem Gerät gespeichert — öffne die App erneut und spiele sie wieder ab.","features.items.6.title":"Vordergrunddienst","features.items.6.text":"Ein nativer Vordergrunddienst sendet die Position weiter, auch wenn die App im Hintergrund ist.","multilingual.heading":"Mehrsprachige Oberfläche","multilingual.body":"Die App-Oberfläche selbst ist in mehrere Sprachen übersetzt und wechselt sofort — praktisch, wenn du denselben Ablauf in verschiedenen Sprachen testest.","multilingual.alt_a":"Route-Spoofer-Oberfläche auf Chinesisch","multilingual.alt_b":"Route-Spoofer-Oberfläche auf Spanisch","how.heading":"So funktioniert’s","how.body":"Eine mit HTML und JavaScript erstellte Capacitor-7-Weboberfläche übernimmt das Zeichnen und die Vorschau der Route. Ein nativer Kotlin-Vordergrunddienst speist die Position in die Android-Testprovider GPS und NETWORK ein, sodass sie das gesamte System erreicht. Route Spoofer muss als System-Mock-Standort-App ausgewählt sein. Das Projekt wird mit dem JDK-21-Toolchain gebaut.","how.chips.0":"Capacitor 7 Weboberfläche","how.chips.1":"Kotlin-Vordergrunddienst","how.chips.2":"GPS- + NETWORK-Mock-Provider","how.chips.3":"JDK 21","setup.heading":"Anleitung","setup.intro":"Eine einmalige Einrichtung des Telefons, dann auf Play drücken. Die beiden Screenshots unten zeigen die Schritte im Entwicklermodus.","setup.steps_title":"Telefon einrichten","setup.steps.0.n":"1","setup.steps.0.title":"Entwickleroptionen aktivieren","setup.steps.0.text":"Öffne Einstellungen → Über das Telefon → Softwareinformationen und tippe siebenmal auf die Build-Nummer, um die Entwickleroptionen freizuschalten.","setup.steps.1.n":"2","setup.steps.1.title":"App installieren","setup.steps.1.text":"Erlaube Installationen aus unbekannten Quellen und übertrage die Datei app-debug.apk per Sideload auf das Telefon.","setup.steps.2.n":"3","setup.steps.2.title":"Mock-Standort-App auswählen","setup.steps.2.text":"Öffne in den Entwickleroptionen „App für simulierte Standorte“ und wähle Route Spoofer.","setup.steps.3.n":"4","setup.steps.3.title":"Starten & freigeben","setup.steps.3.text":"Öffne Route Spoofer, erteile Standort und Benachrichtigungen, warte auf die Bereitschaftskarte und drücke dann auf Play.","setup.shot_a_alt":"Bildschirm Softwareinformationen — tippe auf die Build-Nummer, um die Entwickleroptionen zu aktivieren","setup.shot_b_alt":"App-interne Bereitschaftskarte, die auffordert, Route Spoofer als Mock-Standort-App auszuwählen","setup.build_title":"APK beziehen","setup.builds.0.title":"Cloud-Build","setup.builds.0.text":"GitHub Actions baut die App — lade das Artefakt app-debug.apk aus dem Workflow-Lauf herunter.","setup.builds.1.title":"Lokaler Build","setup.builds.1.text":"Oder baue sie selbst in Android Studio mit JDK 21 und dem Android SDK.","platform.heading":"Plattform-Unterstützung","platform.body":"Nur Android. iOS hat keine öffentliche Mock-Standort-API und kann daher nicht unterstützt werden.","platform.android":"Android — unterstützt","platform.ios":"iOS — nicht unterstützt","license.heading":"Lizenz","license.body":"Veröffentlicht unter der MIT-Lizenz — © 2026 Maxim Popelnitskiy. Frei nutzbar, veränderbar und verteilbar.","footer.tagline":"Android-Routenplayer mit Mock-GPS zum Testen standortbasierter Apps.","footer.github":"Auf GitHub ansehen","footer.license":"MIT-Lizenz","footer.author":"von Maxim Popelnitskiy","footer.rights":"© 2026 Maxim Popelnitskiy","footer.privacy":"Datenschutz","footer.cookies":"Cookies","lang_label":"Sprache","privacy.title":"Datenschutzerklärung — Route Spoofer","privacy.desc":"Datenschutzerklärung der Route-Spoofer-Android-App und dieser Website: keine Konten, keine Analyse, keine Erhebung personenbezogener Daten.","privacy.heading":"Datenschutzerklärung","privacy.intro":"Route Spoofer ist eine quelloffene (MIT) Android-App, mit der Entwickler und QA eine vorgegebene GPS-Route abspielen können, um standortbasierte Apps zu testen. Diese Erklärung gilt für die App und diese Website.","privacy.app_heading":"Die App","privacy.app.0":"Kein Konto, keine Anmeldung.","privacy.app.1":"Erhebt keine personenbezogenen Daten und sendet nichts an einen Server. Keine Analyse, keine Werbung, keine Tracking-SDKs von Dritten.","privacy.app.2":"Die Standortberechtigung wird nur auf deinem Gerät verwendet, um eine Mock-GPS-Position auszugeben; dein Standort wird nicht remote gespeichert oder übertragen.","privacy.app.3":"Die Benachrichtigungsberechtigung dient nur dazu, die Statusbenachrichtigung des Vordergrunddienstes anzuzeigen.","privacy.app.4":"Die von dir gezeichnete Route wird lokal auf deinem Gerät gespeichert; lösche die App-Daten oder deinstalliere die App, um sie zu entfernen.","privacy.web_heading":"Diese Website","privacy.web.0":"Eine statische Informationsseite. Keine Anmeldung, keine Kontaktformulare, keine Erhebung personenbezogener Daten.","privacy.web.1":"Deine Sprachwahl wird im localStorage deines Browsers gespeichert, damit die Seite sie sich merkt; sie bleibt auf deinem Gerät und wird nie an uns gesendet.","privacy.web.2":"Der Hosting-Anbieter führt übliche Server-Anfrageprotokolle (IP-Adresse, User Agent, Zeitstempel) zur Sicherheit und zum Betrieb. Diese Seite wird von GitHub, Inc. gehostet.","privacy.closing":"Wir verkaufen oder teilen keine Daten. Da wir keine personenbezogenen Daten erheben, gibt es auf unserer Seite nichts, worauf zugegriffen, was korrigiert oder gelöscht werden könnte; die Daten auf dem Gerät liegen vollständig in deiner Hand.","privacy.contact_label":"Kontakt:","privacy.contact_link":"GitHub Issues","privacy.updated_label":"Zuletzt aktualisiert:","privacy.updated":"2026-06-25","cookies.title":"Cookies & lokaler Speicher — Route Spoofer","cookies.desc":"Cookie-Hinweis der Route-Spoofer-Website: keine Tracking- oder Werbe-Cookies; ein funktionaler Spracheintrag im localStorage.","cookies.heading":"Cookies & lokaler Speicher","cookies.body.0":"Diese Website verwendet keine Tracking-, Analyse- oder Werbe-Cookies und keine Cookies von Dritten.","cookies.body.1":"Diese Seite setzt überhaupt keine Cookies.","cookies.body.2":"Sie speichert einen funktionalen Eintrag im localStorage deines Browsers — deine gewählte Sprache („route-spoofer.lang\") —, damit beim nächsten Besuch deine bevorzugte Sprache angezeigt wird. Er bleibt auf deinem Gerät, wird nicht an uns gesendet, und du kannst ihn jederzeit in den Browsereinstellungen löschen.","cookies.body.3":"Der Host führt übliche Server-Protokolle wie in der Datenschutzerklärung beschrieben. Da keine Tracking-Technologien verwendet werden, gibt es kein Einwilligungsbanner.","cookies.updated_label":"Zuletzt aktualisiert:","cookies.updated":"2026-06-25"},"es":{"nav.features":"Funciones","nav.maps":"Apps de mapas","nav.how":"Cómo funciona","nav.setup":"Cómo usar","hero.badge":"Android · GPS simulado · MIT","hero.tagline":"Reproductor de rutas con GPS simulado para Android: recorre una ruta predefinida a una velocidad fija para probar apps basadas en ubicación.","hero.cta":"Ver en GitHub","hero.cta2":"Cómo usar","hero.download":"Descargar APK","hero.shot_alt":"Pantalla principal de Route Spoofer con una ruta de varios puntos en el mapa","what.heading":"Qué es","what.body":"Route Spoofer es una app independiente de Android que inyecta una ubicación GPS predefinida y en movimiento en todo el dispositivo. Dibujas una ruta, fijas una velocidad y pulsas Play, y cualquier otra app del teléfono lee la posición simulada como si estuvieras allí de verdad. Sin root y sin herramientas de escritorio: funciona por completo en el teléfono.","who.heading":"Para quién es","who.intro":"Pensado para ingenieros de QA y desarrolladores que trabajan en apps basadas en ubicación: productos de conducción, navegación, entrega y despacho.","who.items.0.title":"Prueba sin moverte","who.items.0.text":"Ejercita una app de conducción, navegación, entrega o despacho desde tu escritorio en lugar de recorrer una ruta real a pie o en coche.","who.items.1.title":"Reproducción repetible","who.items.1.text":"Repite exactamente la misma ruta a exactamente la misma velocidad en cada ejecución: ideal para pruebas de regresión y reproducir errores.","who.items.2.title":"Demos creíbles","who.items.2.text":"Muestra una plataforma de transporte o despacho con un viaje en movimiento realista, sin enviar a nadie a la calle.","maps.heading":"Funciona con cualquier app de mapas","maps.body":"Como la ubicación se inyecta a nivel del sistema, la posición falsa aparece en todas partes, no solo dentro de Route Spoofer. Abre Google Maps, Yandex Maps, Maps.me o cualquier navegador y observa cómo el marcador sigue tu ruta predefinida.","maps.banner_alt":"Aviso del sistema de Android «La ubicación simulada está activada»","maps.tiles.0.label":"Google Maps","maps.tiles.0.alt":"Ubicación simulada mostrada en Google Maps","maps.tiles.1.label":"Yandex Maps","maps.tiles.1.alt":"Ubicación simulada mostrada en Yandex Maps","maps.tiles.2.label":"Maps.me","maps.tiles.2.alt":"Ubicación simulada mostrada en Maps.me","maps.tiles.3.label":"2GIS","maps.tiles.3.alt":"Ubicación simulada mostrada en 2GIS","features.heading":"Funciones","features.items.0.title":"Rutas de varios puntos","features.items.0.text":"Toca A → B → C … para dibujar una ruta; Route Spoofer interpola un trazado suave entre los puntos.","features.items.1.title":"Velocidad e intervalo","features.items.1.text":"Ajusta la velocidad de reproducción en km/h y la frecuencia con la que se emite una posición.","features.items.2.title":"Reproducir · Pausar · Detener","features.items.2.text":"Inicia, pausa y detén la reproducción en cualquier momento.","features.items.3.title":"Modos de bucle","features.items.3.text":"Elige bucle desactivado, reinicio desde el principio o ida y vuelta a lo largo de la ruta.","features.items.4.title":"Telemetría en vivo","features.items.4.text":"Un HUD muestra velocidad, rumbo, progreso y distancia, con un registro continuo de los puntos emitidos.","features.items.5.title":"Guardado localmente","features.items.5.text":"Tu ruta se guarda en el dispositivo: vuelve a abrir la app y reprodúcela de nuevo.","features.items.6.title":"Servicio en primer plano","features.items.6.text":"Un servicio nativo en primer plano sigue emitiendo la ubicación incluso con la app en segundo plano.","multilingual.heading":"Interfaz multilingüe","multilingual.body":"La propia interfaz de la app está traducida a varios idiomas y cambia al instante: práctico cuando pruebas el mismo flujo en distintos idiomas.","multilingual.alt_a":"Interfaz de Route Spoofer en chino","multilingual.alt_b":"Interfaz de Route Spoofer en español","how.heading":"Cómo funciona","how.body":"Una interfaz web Capacitor 7 hecha con HTML y JavaScript se encarga de dibujar y previsualizar la ruta. Un servicio nativo en primer plano en Kotlin inyecta la posición en los proveedores de prueba GPS y NETWORK de Android, de modo que llega a todo el sistema. Route Spoofer debe estar seleccionada como la app de ubicación simulada del sistema. El proyecto se compila con la cadena de herramientas JDK 21.","how.chips.0":"Interfaz web Capacitor 7","how.chips.1":"Servicio Kotlin en primer plano","how.chips.2":"Proveedores simulados GPS + NETWORK","how.chips.3":"JDK 21","setup.heading":"Cómo usar","setup.intro":"Una configuración única del teléfono y luego pulsa Play. Las dos capturas de abajo muestran los pasos del modo desarrollador.","setup.steps_title":"Configuración del teléfono","setup.steps.0.n":"1","setup.steps.0.title":"Activa las opciones de desarrollador","setup.steps.0.text":"Abre Ajustes → Información del teléfono → Información de software y toca «Número de compilación» siete veces para desbloquear las opciones de desarrollador.","setup.steps.1.n":"2","setup.steps.1.title":"Instala la app","setup.steps.1.text":"Permite instalaciones de fuentes desconocidas e instala manualmente el archivo app-debug.apk en el teléfono.","setup.steps.2.n":"3","setup.steps.2.title":"Selecciona la app de ubicación simulada","setup.steps.2.text":"En las opciones de desarrollador abre «Aplicación de ubicaciones simuladas» y elige Route Spoofer.","setup.steps.3.n":"4","setup.steps.3.title":"Abre y concede permisos","setup.steps.3.text":"Abre Route Spoofer, concede Ubicación y Notificaciones, espera la tarjeta de listo y pulsa Play.","setup.shot_a_alt":"Pantalla de información de software: toca «Número de compilación» para activar las opciones de desarrollador","setup.shot_b_alt":"Tarjeta de listo dentro de la app que pide seleccionar Route Spoofer como app de ubicación simulada","setup.build_title":"Consigue el APK","setup.builds.0.title":"Compilación en la nube","setup.builds.0.text":"GitHub Actions compila la app: descarga el artefacto app-debug.apk de la ejecución del workflow.","setup.builds.1.title":"Compilación local","setup.builds.1.text":"O compílala tú mismo en Android Studio con JDK 21 y el SDK de Android.","platform.heading":"Compatibilidad de plataformas","platform.body":"Solo Android. iOS no tiene una API pública de ubicación simulada, por lo que no es compatible.","platform.android":"Android — compatible","platform.ios":"iOS — no compatible","license.heading":"Licencia","license.body":"Publicado bajo la Licencia MIT — © 2026 Maxim Popelnitskiy. Libre para usar, modificar y distribuir.","footer.tagline":"Reproductor de rutas con GPS simulado para Android para probar apps basadas en ubicación.","footer.github":"Ver en GitHub","footer.license":"Licencia MIT","footer.author":"por Maxim Popelnitskiy","footer.rights":"© 2026 Maxim Popelnitskiy","footer.privacy":"Privacidad","footer.cookies":"Cookies","lang_label":"Idioma","privacy.title":"Política de privacidad — Route Spoofer","privacy.desc":"Política de privacidad de la app Route Spoofer para Android y de este sitio: sin cuentas, sin analíticas, sin recopilación de datos personales.","privacy.heading":"Política de privacidad","privacy.intro":"Route Spoofer es una app de Android de código abierto (MIT) para que desarrolladores y QA reproduzcan una ruta GPS predefinida al probar apps basadas en ubicación. Esta política cubre la app y este sitio web.","privacy.app_heading":"La app","privacy.app.0":"Sin cuenta, sin registro.","privacy.app.1":"No recopila datos personales y no envía nada a ningún servidor. Sin analíticas, sin publicidad, sin SDK de rastreo de terceros.","privacy.app.2":"El permiso de Ubicación se usa solo en tu dispositivo para emitir una ubicación GPS simulada; tu ubicación nunca se almacena de forma remota ni se transmite.","privacy.app.3":"El permiso de Notificaciones se usa solo para mostrar la notificación de estado del servicio en primer plano.","privacy.app.4":"La ruta que dibujas se guarda localmente en tu dispositivo; borra los datos de la app o desinstálala para eliminarla.","privacy.web_heading":"Este sitio web","privacy.web.0":"Un sitio informativo estático. Sin registro, sin formularios de contacto, sin recopilación de datos personales.","privacy.web.1":"Tu elección de idioma se guarda en el localStorage de tu navegador para que el sitio la recuerde; permanece en tu dispositivo y nunca se nos envía.","privacy.web.2":"El proveedor de alojamiento conserva registros estándar de solicitudes del servidor (dirección IP, agente de usuario, marca de tiempo) por seguridad y funcionamiento. Este sitio está alojado por GitHub, Inc.","privacy.closing":"No vendemos ni compartimos datos. Como no recopilamos datos personales, no hay nada de nuestro lado a lo que acceder, que corregir o eliminar; los datos en el dispositivo están totalmente bajo tu control.","privacy.contact_label":"Contacto:","privacy.contact_link":"GitHub issues","privacy.updated_label":"Última actualización:","privacy.updated":"2026-06-25","cookies.title":"Cookies y almacenamiento local — Route Spoofer","cookies.desc":"Aviso de cookies del sitio Route Spoofer: sin cookies de rastreo ni publicidad; un elemento funcional de idioma en localStorage.","cookies.heading":"Cookies y almacenamiento local","cookies.body.0":"Este sitio web no usa cookies de rastreo, analíticas ni publicitarias, ni cookies de terceros.","cookies.body.1":"Este sitio no establece ninguna cookie.","cookies.body.2":"Guarda un elemento funcional en el localStorage de tu navegador — el idioma que elegiste («route-spoofer.lang») — para mostrar tu idioma preferido al volver. Permanece en tu dispositivo, no se nos envía y puedes borrarlo cuando quieras en los ajustes del navegador.","cookies.body.3":"El host conserva registros estándar del servidor como se describe en la Política de privacidad. Como no se usan tecnologías de rastreo, no hay banner de consentimiento.","cookies.updated_label":"Última actualización:","cookies.updated":"2026-06-25"},"pt":{"nav.features":"Recursos","nav.maps":"Apps de mapas","nav.how":"Como funciona","nav.setup":"Como usar","hero.badge":"Android · GPS falso · MIT","hero.tagline":"Reprodutor de rotas com GPS falso para Android — percorra uma rota predefinida a uma velocidade fixa para testar apps baseados em localização.","hero.cta":"Ver no GitHub","hero.cta2":"Como usar","hero.download":"Baixar APK","hero.shot_alt":"Tela principal do Route Spoofer com uma rota de vários pontos no mapa","what.heading":"O que é","what.body":"O Route Spoofer é um app independente de Android que injeta uma localização GPS predefinida e em movimento em todo o aparelho. Você desenha uma rota, define uma velocidade e toca em Play — e qualquer outro app do telefone lê a posição simulada como se você estivesse mesmo ali. Sem root e sem ferramenta de desktop: tudo roda no próprio telefone.","who.heading":"Para quem é","who.intro":"Feito para engenheiros de QA e desenvolvedores que trabalham em apps baseados em localização — produtos de motorista, navegação, entrega e despacho.","who.items.0.title":"Teste sem se mover","who.items.0.text":"Exercite um app de motorista, navegação, entrega ou despacho da sua mesa, em vez de percorrer uma rota real a pé ou de carro.","who.items.1.title":"Reprodução repetível","who.items.1.text":"Repita exatamente a mesma rota na mesma velocidade a cada execução — ideal para testes de regressão e reprodução de bugs.","who.items.2.title":"Demos convincentes","who.items.2.text":"Mostre uma plataforma de transporte ou despacho com uma viagem em movimento realista, sem mandar ninguém para a rua.","maps.heading":"Funciona com qualquer app de mapas","maps.body":"Como a localização é injetada no nível do sistema, a posição falsa aparece em todo lugar — não só dentro do Route Spoofer. Abra o Google Maps, o Yandex Maps, o Maps.me ou qualquer navegador e veja o marcador seguir a sua rota predefinida.","maps.banner_alt":"Aviso do sistema Android «A localização fictícia está ativada»","maps.tiles.0.label":"Google Maps","maps.tiles.0.alt":"Localização falsa exibida no Google Maps","maps.tiles.1.label":"Yandex Maps","maps.tiles.1.alt":"Localização falsa exibida no Yandex Maps","maps.tiles.2.label":"Maps.me","maps.tiles.2.alt":"Localização falsa exibida no Maps.me","maps.tiles.3.label":"2GIS","maps.tiles.3.alt":"Localização falsa exibida no 2GIS","features.heading":"Recursos","features.items.0.title":"Rotas de vários pontos","features.items.0.text":"Toque em A → B → C … para desenhar uma rota; o Route Spoofer interpola um caminho suave entre os pontos.","features.items.1.title":"Velocidade e intervalo","features.items.1.text":"Defina a velocidade de reprodução em km/h e a frequência com que uma posição é emitida.","features.items.2.title":"Reproduzir · Pausar · Parar","features.items.2.text":"Inicie, pause e pare a reprodução a qualquer momento.","features.items.3.title":"Modos de repetição","features.items.3.text":"Escolha repetição desligada, reinício do começo ou vai e volta ao longo da rota.","features.items.4.title":"Telemetria ao vivo","features.items.4.text":"Um HUD mostra velocidade, direção, progresso e distância, com um registro contínuo dos pontos emitidos.","features.items.5.title":"Salvo localmente","features.items.5.text":"Sua rota fica salva no aparelho — reabra o app e reproduza novamente.","features.items.6.title":"Serviço em primeiro plano","features.items.6.text":"Um serviço nativo em primeiro plano continua emitindo a localização mesmo com o app em segundo plano.","multilingual.heading":"Interface multilíngue","multilingual.body":"A própria interface do app é traduzida para vários idiomas e muda na hora — útil quando você testa o mesmo fluxo em vários idiomas.","multilingual.alt_a":"Interface do Route Spoofer em chinês","multilingual.alt_b":"Interface do Route Spoofer em espanhol","how.heading":"Como funciona","how.body":"Uma interface web em Capacitor 7 feita com HTML e JavaScript cuida do desenho e da prévia da rota. Um serviço nativo em primeiro plano em Kotlin injeta a posição nos provedores de teste GPS e NETWORK do Android, de modo que ela alcança todo o sistema. O Route Spoofer precisa estar selecionado como o app de localização fictícia do sistema. O projeto é compilado com o toolchain JDK 21.","how.chips.0":"Interface web Capacitor 7","how.chips.1":"Serviço Kotlin em primeiro plano","how.chips.2":"Provedores simulados GPS + NETWORK","how.chips.3":"JDK 21","setup.heading":"Como usar","setup.intro":"Uma configuração única do telefone e depois toque em Play. As duas capturas abaixo mostram os passos do modo desenvolvedor.","setup.steps_title":"Configuração do telefone","setup.steps.0.n":"1","setup.steps.0.title":"Ative as opções do desenvolvedor","setup.steps.0.text":"Abra Configurações → Sobre o telefone → Informações de software e toque em «Número da versão» sete vezes para desbloquear as opções do desenvolvedor.","setup.steps.1.n":"2","setup.steps.1.title":"Instale o app","setup.steps.1.text":"Permita instalações de fontes desconhecidas e faça o sideload do arquivo app-debug.apk no telefone.","setup.steps.2.n":"3","setup.steps.2.title":"Selecione o app de localização fictícia","setup.steps.2.text":"Nas opções do desenvolvedor, abra «Aplicativo de localização fictícia» e escolha o Route Spoofer.","setup.steps.3.n":"4","setup.steps.3.title":"Abra e conceda permissões","setup.steps.3.text":"Abra o Route Spoofer, conceda Localização e Notificações, aguarde o cartão de prontidão e toque em Play.","setup.shot_a_alt":"Tela de informações de software — toque em «Número da versão» para ativar as opções do desenvolvedor","setup.shot_b_alt":"Cartão de prontidão no app pedindo para selecionar o Route Spoofer como app de localização fictícia","setup.build_title":"Obtenha o APK","setup.builds.0.title":"Build na nuvem","setup.builds.0.text":"O GitHub Actions compila o app — baixe o artefato app-debug.apk da execução do workflow.","setup.builds.1.title":"Build local","setup.builds.1.text":"Ou compile você mesmo no Android Studio com o JDK 21 e o Android SDK.","platform.heading":"Suporte de plataforma","platform.body":"Apenas Android. O iOS não tem uma API pública de localização fictícia, por isso não há suporte.","platform.android":"Android — compatível","platform.ios":"iOS — sem suporte","license.heading":"Licença","license.body":"Lançado sob a Licença MIT — © 2026 Maxim Popelnitskiy. Livre para usar, modificar e distribuir.","footer.tagline":"Reprodutor de rotas com GPS falso para Android para testar apps baseados em localização.","footer.github":"Ver no GitHub","footer.license":"Licença MIT","footer.author":"por Maxim Popelnitskiy","footer.rights":"© 2026 Maxim Popelnitskiy","footer.privacy":"Privacidade","footer.cookies":"Cookies","lang_label":"Idioma","privacy.title":"Política de Privacidade — Route Spoofer","privacy.desc":"Política de privacidade do app Route Spoofer para Android e deste site: sem contas, sem analytics, sem coleta de dados pessoais.","privacy.heading":"Política de Privacidade","privacy.intro":"O Route Spoofer é um app Android de código aberto (MIT) para desenvolvedores e QA reproduzirem uma rota GPS predefinida ao testar apps baseados em localização. Esta política cobre o app e este site.","privacy.app_heading":"O app","privacy.app.0":"Sem conta, sem cadastro.","privacy.app.1":"Não coleta dados pessoais e não envia nada a nenhum servidor. Sem analytics, sem publicidade, sem SDKs de rastreamento de terceiros.","privacy.app.2":"A permissão de Localização é usada apenas no seu aparelho para emitir uma localização GPS falsa; sua localização nunca é armazenada remotamente nem transmitida.","privacy.app.3":"A permissão de Notificações é usada apenas para mostrar a notificação de status do serviço em primeiro plano.","privacy.app.4":"A rota que você desenha fica salva localmente no seu aparelho; limpe os dados do app ou desinstale-o para removê-la.","privacy.web_heading":"Este site","privacy.web.0":"Um site informativo estático. Sem cadastro, sem formulários de contato, sem coleta de dados pessoais.","privacy.web.1":"Sua escolha de idioma fica no localStorage do seu navegador para que o site a lembre; ela permanece no seu aparelho e nunca é enviada a nós.","privacy.web.2":"O provedor de hospedagem mantém registros padrão de requisições do servidor (endereço IP, user agent, data e hora) para segurança e operação. Este site é hospedado pela GitHub, Inc.","privacy.closing":"Não vendemos nem compartilhamos dados. Como não coletamos dados pessoais, não há nada do nosso lado para acessar, corrigir ou excluir; os dados no aparelho estão totalmente sob seu controle.","privacy.contact_label":"Contato:","privacy.contact_link":"GitHub issues","privacy.updated_label":"Última atualização:","privacy.updated":"2026-06-25","cookies.title":"Cookies e armazenamento local — Route Spoofer","cookies.desc":"Aviso de cookies do site Route Spoofer: sem cookies de rastreamento ou publicidade; um item funcional de idioma no localStorage.","cookies.heading":"Cookies e armazenamento local","cookies.body.0":"Este site não usa cookies de rastreamento, analytics ou publicidade, nem cookies de terceiros.","cookies.body.1":"Este site não define nenhum cookie.","cookies.body.2":"Ele mantém um item funcional no localStorage do seu navegador — o idioma que você escolheu («route-spoofer.lang») — para mostrar seu idioma preferido no retorno. Ele permanece no seu aparelho, não é enviado a nós, e você pode apagá-lo a qualquer momento nas configurações do navegador.","cookies.body.3":"O host mantém registros padrão do servidor conforme descrito na Política de Privacidade. Como nenhuma tecnologia de rastreamento é usada, não há banner de consentimento.","cookies.updated_label":"Última atualização:","cookies.updated":"2026-06-25"},"fr":{"nav.features":"Fonctions","nav.maps":"Apps de cartes","nav.how":"Comment ça marche","nav.setup":"Utilisation","hero.badge":"Android · GPS fictif · MIT","hero.tagline":"Lecteur de trajets avec GPS fictif pour Android — parcourez un trajet prédéfini à une vitesse définie pour tester les applis géolocalisées.","hero.cta":"Voir sur GitHub","hero.cta2":"Utilisation","hero.download":"Télécharger l’APK","hero.shot_alt":"Écran principal de Route Spoofer avec un trajet à plusieurs points sur la carte","what.heading":"Qu’est-ce que c’est","what.body":"Route Spoofer est une application Android autonome qui injecte une position GPS prédéfinie et mobile dans tout l’appareil. Vous tracez un trajet, réglez une vitesse et appuyez sur Lecture — et toutes les autres applis du téléphone lisent la position simulée comme si vous y étiez vraiment. Pas de root, pas d’outil sur ordinateur : tout fonctionne sur le téléphone.","who.heading":"À qui ça s’adresse","who.intro":"Conçu pour les ingénieurs QA et les développeurs d’applis géolocalisées — chauffeur, navigation, livraison et répartition.","who.items.0.title":"Tester sans bouger","who.items.0.text":"Faites fonctionner une appli chauffeur, navigation, livraison ou répartition depuis votre bureau, au lieu de parcourir un vrai trajet à pied ou en voiture.","who.items.1.title":"Lecture reproductible","who.items.1.text":"Rejouez exactement le même trajet à exactement la même vitesse à chaque exécution — idéal pour les tests de régression et la reproduction de bugs.","who.items.2.title":"Démos crédibles","who.items.2.text":"Présentez une plateforme de VTC ou de répartition avec un trajet réaliste en mouvement, sans envoyer personne dehors.","maps.heading":"Fonctionne avec n’importe quelle appli de cartes","maps.body":"Comme la position est injectée au niveau du système, la fausse position apparaît partout — pas seulement dans Route Spoofer. Ouvrez Google Maps, Yandex Maps, Maps.me ou n’importe quel navigateur et regardez le marqueur suivre votre trajet prédéfini.","maps.banner_alt":"Bannière système Android « La position fictive est activée »","maps.tiles.0.label":"Google Maps","maps.tiles.0.alt":"Position fictive affichée dans Google Maps","maps.tiles.1.label":"Yandex Maps","maps.tiles.1.alt":"Position fictive affichée dans Yandex Maps","maps.tiles.2.label":"Maps.me","maps.tiles.2.alt":"Position fictive affichée dans Maps.me","maps.tiles.3.label":"2GIS","maps.tiles.3.alt":"Position fictive affichée dans 2GIS","features.heading":"Fonctions","features.items.0.title":"Trajets multipoints","features.items.0.text":"Touchez A → B → C … pour tracer un trajet ; Route Spoofer interpole un chemin fluide entre les points.","features.items.1.title":"Vitesse et intervalle","features.items.1.text":"Réglez la vitesse de lecture en km/h et la fréquence d’émission d’une position.","features.items.2.title":"Lecture · Pause · Arrêt","features.items.2.text":"Démarrez, mettez en pause et arrêtez la lecture à tout moment.","features.items.3.title":"Modes de boucle","features.items.3.text":"Choisissez boucle désactivée, redémarrage depuis le début ou aller-retour le long du trajet.","features.items.4.title":"Télémétrie en direct","features.items.4.text":"Un HUD affiche la vitesse, le cap, la progression et la distance, avec un journal en continu des points émis.","features.items.5.title":"Enregistré localement","features.items.5.text":"Votre trajet est stocké sur l’appareil — rouvrez l’appli et rejouez-le.","features.items.6.title":"Service de premier plan","features.items.6.text":"Un service natif de premier plan continue d’émettre la position même lorsque l’appli est en arrière-plan.","multilingual.heading":"Interface multilingue","multilingual.body":"L’interface de l’appli elle-même est traduite en plusieurs langues et change instantanément — pratique pour tester le même parcours dans différentes langues.","multilingual.alt_a":"Interface de Route Spoofer en chinois","multilingual.alt_b":"Interface de Route Spoofer en espagnol","how.heading":"Comment ça marche","how.body":"Une interface web Capacitor 7 réalisée en HTML et JavaScript gère le tracé et l’aperçu du trajet. Un service natif de premier plan en Kotlin injecte la position dans les fournisseurs de test GPS et NETWORK d’Android, afin qu’elle atteigne tout le système. Route Spoofer doit être sélectionnée comme appli de position fictive du système. Le projet est compilé avec la chaîne d’outils JDK 21.","how.chips.0":"Interface web Capacitor 7","how.chips.1":"Service Kotlin de premier plan","how.chips.2":"Fournisseurs fictifs GPS + NETWORK","how.chips.3":"JDK 21","setup.heading":"Utilisation","setup.intro":"Une configuration unique du téléphone, puis appuyez sur Lecture. Les deux captures ci-dessous montrent les étapes du mode développeur.","setup.steps_title":"Configuration du téléphone","setup.steps.0.n":"1","setup.steps.0.title":"Activez les options pour développeurs","setup.steps.0.text":"Ouvrez Paramètres → À propos du téléphone → Informations sur le logiciel et touchez sept fois le « Numéro de build » pour débloquer les options pour développeurs.","setup.steps.1.n":"2","setup.steps.1.title":"Installez l’appli","setup.steps.1.text":"Autorisez les installations de sources inconnues et transférez le fichier app-debug.apk sur le téléphone (sideload).","setup.steps.2.n":"3","setup.steps.2.title":"Sélectionnez l’appli de position fictive","setup.steps.2.text":"Dans les options pour développeurs, ouvrez « Application de position fictive » et choisissez Route Spoofer.","setup.steps.3.n":"4","setup.steps.3.title":"Lancez et autorisez","setup.steps.3.text":"Ouvrez Route Spoofer, accordez la Localisation et les Notifications, attendez la carte de disponibilité, puis appuyez sur Lecture.","setup.shot_a_alt":"Écran Informations sur le logiciel — touchez le « Numéro de build » pour activer les options pour développeurs","setup.shot_b_alt":"Carte de disponibilité dans l’appli demandant de sélectionner Route Spoofer comme appli de position fictive","setup.build_title":"Obtenir l’APK","setup.builds.0.title":"Build dans le cloud","setup.builds.0.text":"GitHub Actions compile l’appli — téléchargez l’artefact app-debug.apk depuis l’exécution du workflow.","setup.builds.1.title":"Build local","setup.builds.1.text":"Ou compilez-la vous-même dans Android Studio avec le JDK 21 et le SDK Android.","platform.heading":"Plateformes prises en charge","platform.body":"Android uniquement. iOS ne propose pas d’API publique de position fictive, il ne peut donc pas être pris en charge.","platform.android":"Android — pris en charge","platform.ios":"iOS — non pris en charge","license.heading":"Licence","license.body":"Publié sous licence MIT — © 2026 Maxim Popelnitskiy. Libre d’utilisation, de modification et de distribution.","footer.tagline":"Lecteur de trajets avec GPS fictif pour Android, pour tester les applis géolocalisées.","footer.github":"Voir sur GitHub","footer.license":"Licence MIT","footer.author":"par Maxim Popelnitskiy","footer.rights":"© 2026 Maxim Popelnitskiy","footer.privacy":"Confidentialité","footer.cookies":"Cookies","lang_label":"Langue","privacy.title":"Politique de confidentialité — Route Spoofer","privacy.desc":"Politique de confidentialité de l'application Route Spoofer pour Android et de ce site : pas de comptes, pas d'analyse, aucune donnée personnelle collectée.","privacy.heading":"Politique de confidentialité","privacy.intro":"Route Spoofer est une application Android open source (MIT) permettant aux développeurs et au QA de rejouer un trajet GPS prédéfini pour tester des applis géolocalisées. Cette politique couvre l'application et ce site.","privacy.app_heading":"L'application","privacy.app.0":"Pas de compte, pas d'inscription.","privacy.app.1":"Ne collecte aucune donnée personnelle et n'envoie rien à un serveur. Pas d'analyse, pas de publicité, pas de SDK de pistage tiers.","privacy.app.2":"L'autorisation de localisation est utilisée uniquement sur votre appareil pour émettre une position GPS fictive ; votre position n'est jamais stockée à distance ni transmise.","privacy.app.3":"L'autorisation de notifications sert uniquement à afficher la notification d'état du service de premier plan.","privacy.app.4":"Le trajet que vous tracez est stocké localement sur votre appareil ; effacez les données de l'appli ou désinstallez-la pour le supprimer.","privacy.web_heading":"Ce site web","privacy.web.0":"Un site informatif statique. Pas d'inscription, pas de formulaire de contact, aucune donnée personnelle collectée.","privacy.web.1":"Votre choix de langue est conservé dans le localStorage de votre navigateur pour que le site s'en souvienne ; il reste sur votre appareil et ne nous est jamais envoyé.","privacy.web.2":"L'hébergeur conserve des journaux de requêtes serveur standard (adresse IP, user agent, horodatage) pour la sécurité et le fonctionnement. Ce site est hébergé par GitHub, Inc.","privacy.closing":"Nous ne vendons ni ne partageons de données. Comme nous ne collectons aucune donnée personnelle, il n'y a rien de notre côté à consulter, corriger ou supprimer ; les données sur l'appareil sont entièrement sous votre contrôle.","privacy.contact_label":"Contact :","privacy.contact_link":"GitHub issues","privacy.updated_label":"Dernière mise à jour :","privacy.updated":"2026-06-25","cookies.title":"Cookies et stockage local — Route Spoofer","cookies.desc":"Avis sur les cookies du site Route Spoofer : pas de cookies de pistage ou publicitaires ; un élément fonctionnel de langue dans localStorage.","cookies.heading":"Cookies et stockage local","cookies.body.0":"Ce site n'utilise aucun cookie de pistage, d'analyse ou de publicité, ni aucun cookie tiers.","cookies.body.1":"Ce site ne dépose aucun cookie.","cookies.body.2":"Il conserve un seul élément fonctionnel dans le localStorage de votre navigateur — la langue que vous avez choisie (« route-spoofer.lang ») — afin d'afficher votre langue préférée à votre retour. Il reste sur votre appareil, ne nous est pas envoyé, et vous pouvez l'effacer à tout moment dans les paramètres de votre navigateur.","cookies.body.3":"L'hébergeur conserve des journaux serveur standard, comme décrit dans la Politique de confidentialité. Comme aucune technologie de pistage n'est utilisée, il n'y a pas de bandeau de consentement.","cookies.updated_label":"Dernière mise à jour :","cookies.updated":"2026-06-25"},"zh":{"nav.features":"功能","nav.maps":"地图应用","nav.how":"工作原理","nav.setup":"使用方法","hero.badge":"Android · 模拟 GPS · MIT","hero.tagline":"Android 模拟 GPS 路线播放器——以设定的速度沿预设路线行进，测试基于位置的应用。","hero.cta":"在 GitHub 查看","hero.cta2":"使用方法","hero.download":"下载 APK","hero.shot_alt":"Route Spoofer 主界面，地图上显示多点路线","what.heading":"这是什么","what.body":"Route Spoofer 是一款独立的 Android 应用，它向整部设备注入一个预设的、移动的 GPS 位置。你绘制一条路线、设定速度并点击播放，手机上的其他任何应用都会把模拟位置当作你真实所在的位置来读取。无需 root，也不需要单独的电脑工具:一切都在手机上运行。","who.heading":"适用人群","who.intro":"为开发和测试基于位置的应用的 QA 工程师和开发者而打造——司机、导航、配送和调度类产品。","who.items.0.title":"无需移动即可测试","who.items.0.text":"在工位上即可运行司机、导航、配送或调度应用，无需真正步行或驾车跑一遍路线。","who.items.1.title":"可复现的回放","who.items.1.text":"每次运行都以完全相同的速度重放完全相同的路线——非常适合回归测试和复现缺陷。","who.items.2.title":"可信的演示","who.items.2.text":"用真实移动的行程展示网约车或调度平台，无需派任何人外出。","maps.heading":"适用于任何地图应用","maps.body":"由于位置是在系统层面注入的，虚假位置会出现在任何地方——而不仅仅是在 Route Spoofer 内。打开 Google Maps、Yandex Maps、Maps.me 或任意导航应用，看着标记沿你的预设路线移动。","maps.banner_alt":"Android 系统横幅“模拟位置已开启”","maps.tiles.0.label":"Google Maps","maps.tiles.0.alt":"在 Google Maps 中显示的虚假位置","maps.tiles.1.label":"Yandex Maps","maps.tiles.1.alt":"在 Yandex Maps 中显示的虚假位置","maps.tiles.2.label":"Maps.me","maps.tiles.2.alt":"在 Maps.me 中显示的虚假位置","maps.tiles.3.label":"2GIS","maps.tiles.3.alt":"在 2GIS 中显示的虚假位置","features.heading":"功能","features.items.0.title":"多点路线","features.items.0.text":"点击 A → B → C … 绘制路线；Route Spoofer 会在各点之间插值出平滑路径。","features.items.1.title":"速度与间隔","features.items.1.text":"设置以 km/h 为单位的播放速度，以及发送位置的频率。","features.items.2.title":"播放 · 暂停 · 停止","features.items.2.text":"随时开始、暂停和停止运行。","features.items.3.title":"循环模式","features.items.3.text":"可选择关闭循环、从头重新开始，或沿路线往返。","features.items.4.title":"实时遥测","features.items.4.text":"HUD 显示速度、航向、进度和距离，并实时记录已发送的点。","features.items.5.title":"本地保存","features.items.5.text":"你的路线会保存在设备上——重新打开应用即可再次回放。","features.items.6.title":"前台服务","features.items.6.text":"原生前台服务即使在应用退到后台时也会持续发送位置。","multilingual.heading":"多语言界面","multilingual.body":"应用界面本身已翻译成多种语言并可即时切换——在不同语言下测试同一流程时很方便。","multilingual.alt_a":"中文界面的 Route Spoofer","multilingual.alt_b":"西班牙语界面的 Route Spoofer","how.heading":"工作原理","how.body":"使用 HTML 和 JavaScript 构建的 Capacitor 7 网页界面负责绘制和预览路线。原生 Kotlin 前台服务将位置注入 Android 的 GPS 和 NETWORK 测试提供程序，从而让定位到达整个系统。必须将 Route Spoofer 选为系统的模拟位置应用。项目使用 JDK 21 工具链构建。","how.chips.0":"Capacitor 7 网页界面","how.chips.1":"Kotlin 前台服务","how.chips.2":"GPS + NETWORK 模拟提供程序","how.chips.3":"JDK 21","setup.heading":"使用方法","setup.intro":"对手机进行一次性设置，然后点击播放。下面两张截图展示了开发者模式下的步骤。","setup.steps_title":"手机设置","setup.steps.0.n":"1","setup.steps.0.title":"启用开发者选项","setup.steps.0.text":"打开 设置 → 关于手机 → 软件信息，连续点击“版本号”七次以解锁开发者选项。","setup.steps.1.n":"2","setup.steps.1.title":"安装应用","setup.steps.1.text":"允许来自未知来源的安装，并将 app-debug.apk 文件旁加载到手机上。","setup.steps.2.n":"3","setup.steps.2.title":"选择模拟位置应用","setup.steps.2.text":"在开发者选项中打开“选择模拟位置应用”，选择 Route Spoofer。","setup.steps.3.n":"4","setup.steps.3.title":"启动并授权","setup.steps.3.text":"打开 Route Spoofer，授予位置和通知权限，等待就绪卡片，然后点击播放。","setup.shot_a_alt":"软件信息界面——点击“版本号”以启用开发者选项","setup.shot_b_alt":"应用内就绪卡片，提示将 Route Spoofer 选为模拟位置应用","setup.build_title":"获取 APK","setup.builds.0.title":"云端构建","setup.builds.0.text":"GitHub Actions 会构建应用——从工作流运行中下载 app-debug.apk 构件。","setup.builds.1.title":"本地构建","setup.builds.1.text":"或在 Android Studio 中使用 JDK 21 和 Android SDK 自行构建。","platform.heading":"平台支持","platform.body":"仅支持 Android。iOS 没有公开的模拟位置 API，因此无法支持。","platform.android":"Android — 支持","platform.ios":"iOS — 不支持","license.heading":"许可证","license.body":"基于 MIT 许可证发布 — © 2026 Maxim Popelnitskiy。可自由使用、修改和分发。","footer.tagline":"用于测试基于位置应用的 Android 模拟 GPS 路线播放器。","footer.github":"在 GitHub 查看","footer.license":"MIT 许可证","footer.author":"作者:Maxim Popelnitskiy","footer.rights":"© 2026 Maxim Popelnitskiy","footer.privacy":"隐私","footer.cookies":"Cookies","lang_label":"语言","privacy.title":"隐私政策 — Route Spoofer","privacy.desc":"Route Spoofer Android 应用及本网站的隐私政策：无账户、无分析、不收集个人数据。","privacy.heading":"隐私政策","privacy.intro":"Route Spoofer 是一款开源（MIT）Android 应用，供开发者和 QA 在测试基于位置的应用时播放预设的 GPS 路线。本政策适用于该应用和本网站。","privacy.app_heading":"应用","privacy.app.0":"无需账户，无需注册。","privacy.app.1":"不收集任何个人数据，也不向任何服务器发送数据。无分析、无广告、无第三方跟踪 SDK。","privacy.app.2":"位置权限仅在你的设备上用于发出模拟 GPS 位置；你的位置绝不会被远程存储或传输。","privacy.app.3":"通知权限仅用于显示前台服务的状态通知。","privacy.app.4":"你绘制的路线仅保存在本机；清除应用数据或卸载即可删除。","privacy.web_heading":"本网站","privacy.web.0":"一个静态信息网站。无需注册、无联系表单、不收集个人数据。","privacy.web.1":"你选择的语言保存在浏览器的 localStorage 中，以便网站记住它；它留在你的设备上，绝不会发送给我们。","privacy.web.2":"主机提供商出于安全和运行目的保留标准的服务器请求日志（IP 地址、用户代理、时间戳）。本网站由 GitHub, Inc. 托管。","privacy.closing":"我们不出售也不共享数据。由于我们不收集个人数据，我们这边没有可供访问、更正或删除的内容；设备上的数据完全由你掌控。","privacy.contact_label":"联系：","privacy.contact_link":"GitHub issues","privacy.updated_label":"最后更新：","privacy.updated":"2026-06-25","cookies.title":"Cookies 与本地存储 — Route Spoofer","cookies.desc":"Route Spoofer 网站的 Cookie 说明：无跟踪或广告 Cookie；localStorage 中仅有一个语言功能项。","cookies.heading":"Cookies 与本地存储","cookies.body.0":"本网站不使用任何跟踪、分析或广告 Cookie，也不使用第三方 Cookie。","cookies.body.1":"本网站完全不设置任何 Cookie。","cookies.body.2":"它在浏览器的 localStorage 中保存一个功能项——你选择的语言（“route-spoofer.lang”）——以便你再次访问时显示首选语言。它留在你的设备上，不会发送给我们，你可以随时在浏览器设置中清除它。","cookies.body.3":"主机会保留标准的服务器日志，如隐私政策所述。由于不使用任何跟踪技术，因此没有同意横幅。","cookies.updated_label":"最后更新：","cookies.updated":"2026-06-25"},"hi":{"nav.features":"विशेषताएँ","nav.maps":"मानचित्र ऐप्स","nav.how":"यह कैसे काम करता है","nav.setup":"उपयोग कैसे करें","hero.badge":"Android · मॉक GPS · MIT","hero.tagline":"Android के लिए मॉक GPS रूट प्लेयर — तय गति से एक पूर्वनिर्धारित रूट पर चलें और लोकेशन-आधारित ऐप्स का परीक्षण करें।","hero.cta":"GitHub पर देखें","hero.cta2":"उपयोग कैसे करें","hero.download":"APK डाउनलोड करें","hero.shot_alt":"मानचित्र पर बहु-बिंदु रूट के साथ Route Spoofer की मुख्य स्क्रीन","what.heading":"यह क्या है","what.body":"Route Spoofer एक स्वतंत्र Android ऐप है जो पूरे डिवाइस में एक पूर्वनिर्धारित, चलती हुई GPS लोकेशन भेजता है। आप एक रूट बनाते हैं, गति तय करते हैं और Play दबाते हैं — और फ़ोन का हर दूसरा ऐप उस नकली स्थिति को ऐसे पढ़ता है मानो आप सचमुच वहीं हों। न root चाहिए, न कोई अलग डेस्कटॉप टूल: सब कुछ फ़ोन पर ही चलता है।","who.heading":"यह किसके लिए है","who.intro":"लोकेशन-आधारित ऐप्स पर काम करने वाले QA इंजीनियरों और डेवलपर्स के लिए बनाया गया — ड्राइवर, नेविगेशन, डिलीवरी और डिस्पैच उत्पाद।","who.items.0.title":"बिना हिले-डुले परीक्षण","who.items.0.text":"असली रूट पर पैदल या गाड़ी से जाने के बजाय अपनी डेस्क से ही ड्राइवर, नेविगेशन, डिलीवरी या डिस्पैच ऐप चलाएँ।","who.items.1.title":"दोहराने योग्य प्लेबैक","who.items.1.text":"हर बार ठीक वही रूट ठीक उसी गति पर फिर से चलाएँ — रिग्रेशन परीक्षण और बग दोहराने के लिए आदर्श।","who.items.2.title":"विश्वसनीय डेमो","who.items.2.text":"किसी को बाहर भेजे बिना, यथार्थवादी चलती यात्रा के साथ राइड-हेलिंग या डिस्पैच प्लेटफ़ॉर्म दिखाएँ।","maps.heading":"किसी भी मानचित्र ऐप के साथ काम करता है","maps.body":"चूँकि लोकेशन सिस्टम स्तर पर भेजी जाती है, नकली स्थिति हर जगह दिखती है — सिर्फ़ Route Spoofer के भीतर नहीं। Google Maps, Yandex Maps, Maps.me या कोई भी नेविगेटर खोलें और देखें कि मार्कर आपके पूर्वनिर्धारित रूट पर चलता है।","maps.banner_alt":"Android का सिस्टम बैनर “मॉक लोकेशन चालू है”","maps.tiles.0.label":"Google Maps","maps.tiles.0.alt":"Google Maps में दिखती नकली लोकेशन","maps.tiles.1.label":"Yandex Maps","maps.tiles.1.alt":"Yandex Maps में दिखती नकली लोकेशन","maps.tiles.2.label":"Maps.me","maps.tiles.2.alt":"Maps.me में दिखती नकली लोकेशन","maps.tiles.3.label":"2GIS","maps.tiles.3.alt":"2GIS में दिखती नकली लोकेशन","features.heading":"विशेषताएँ","features.items.0.title":"बहु-बिंदु रूट","features.items.0.text":"रूट बनाने के लिए A → B → C … पर टैप करें; Route Spoofer बिंदुओं के बीच एक सहज पथ बना देता है।","features.items.1.title":"गति और अंतराल","features.items.1.text":"प्लेबैक गति km/h में और स्थिति भेजने की आवृत्ति सेट करें।","features.items.2.title":"प्ले · पॉज़ · स्टॉप","features.items.2.text":"किसी भी समय रन शुरू करें, रोकें और बंद करें।","features.items.3.title":"लूप मोड","features.items.3.text":"लूप बंद, शुरुआत से फिर शुरू, या रूट पर आगे-पीछे में से चुनें।","features.items.4.title":"लाइव टेलीमेट्री","features.items.4.text":"एक HUD गति, दिशा, प्रगति और दूरी दिखाता है, साथ ही भेजे गए बिंदुओं का चालू लॉग।","features.items.5.title":"स्थानीय रूप से सहेजा गया","features.items.5.text":"आपका रूट डिवाइस पर सहेजा जाता है — ऐप दोबारा खोलें और फिर से चलाएँ।","features.items.6.title":"फ़ोरग्राउंड सेवा","features.items.6.text":"एक नेटिव फ़ोरग्राउंड सेवा ऐप के बैकग्राउंड में रहने पर भी लोकेशन भेजती रहती है।","multilingual.heading":"बहुभाषी इंटरफ़ेस","multilingual.body":"ऐप का इंटरफ़ेस स्वयं कई भाषाओं में अनूदित है और तुरंत बदल जाता है — विभिन्न भाषाओं में एक ही प्रवाह का परीक्षण करते समय उपयोगी।","multilingual.alt_a":"चीनी में Route Spoofer का इंटरफ़ेस","multilingual.alt_b":"स्पेनिश में Route Spoofer का इंटरफ़ेस","how.heading":"यह कैसे काम करता है","how.body":"HTML और JavaScript से बना एक Capacitor 7 वेब इंटरफ़ेस रूट बनाने और पूर्वावलोकन को संभालता है। एक नेटिव Kotlin फ़ोरग्राउंड सेवा स्थिति को Android के GPS और NETWORK टेस्ट प्रोवाइडर में भेजती है, ताकि वह पूरे सिस्टम तक पहुँचे। Route Spoofer को सिस्टम की मॉक-लोकेशन ऐप के रूप में चुना जाना चाहिए। यह प्रोजेक्ट JDK 21 टूलचेन से बनाया गया है।","how.chips.0":"Capacitor 7 वेब इंटरफ़ेस","how.chips.1":"Kotlin फ़ोरग्राउंड सेवा","how.chips.2":"GPS + NETWORK मॉक प्रोवाइडर","how.chips.3":"JDK 21","setup.heading":"उपयोग कैसे करें","setup.intro":"फ़ोन की एक बार की सेटअप, फिर Play दबाएँ। नीचे दो स्क्रीनशॉट डेवलपर-मोड के चरण दिखाते हैं।","setup.steps_title":"फ़ोन सेटअप","setup.steps.0.n":"1","setup.steps.0.title":"डेवलपर विकल्प चालू करें","setup.steps.0.text":"सेटिंग → फ़ोन के बारे में → सॉफ़्टवेयर जानकारी खोलें और डेवलपर विकल्प अनलॉक करने के लिए “बिल्ड नंबर” पर सात बार टैप करें।","setup.steps.1.n":"2","setup.steps.1.title":"ऐप इंस्टॉल करें","setup.steps.1.text":"अज्ञात स्रोतों से इंस्टॉल की अनुमति दें और app-debug.apk फ़ाइल को फ़ोन पर साइडलोड करें।","setup.steps.2.n":"3","setup.steps.2.title":"मॉक-लोकेशन ऐप चुनें","setup.steps.2.text":"डेवलपर विकल्प में “मॉक स्थान ऐप चुनें” खोलें और Route Spoofer चुनें।","setup.steps.3.n":"4","setup.steps.3.title":"लॉन्च करें और अनुमति दें","setup.steps.3.text":"Route Spoofer खोलें, स्थान और सूचनाएँ दें, तैयारी कार्ड का इंतज़ार करें, फिर Play दबाएँ।","setup.shot_a_alt":"सॉफ़्टवेयर जानकारी स्क्रीन — डेवलपर विकल्प चालू करने के लिए “बिल्ड नंबर” पर टैप करें","setup.shot_b_alt":"ऐप के भीतर तैयारी कार्ड जो Route Spoofer को मॉक-लोकेशन ऐप के रूप में चुनने को कहता है","setup.build_title":"APK प्राप्त करें","setup.builds.0.title":"क्लाउड बिल्ड","setup.builds.0.text":"GitHub Actions ऐप बनाता है — workflow रन से app-debug.apk आर्टिफ़ैक्ट डाउनलोड करें।","setup.builds.1.title":"लोकल बिल्ड","setup.builds.1.text":"या Android Studio में JDK 21 और Android SDK के साथ इसे स्वयं बनाएँ।","platform.heading":"प्लेटफ़ॉर्म समर्थन","platform.body":"केवल Android। iOS में कोई सार्वजनिक मॉक-लोकेशन API नहीं है, इसलिए इसका समर्थन संभव नहीं है।","platform.android":"Android — समर्थित","platform.ios":"iOS — असमर्थित","license.heading":"लाइसेंस","license.body":"MIT लाइसेंस के तहत जारी — © 2026 Maxim Popelnitskiy। उपयोग, संशोधन और वितरण के लिए स्वतंत्र।","footer.tagline":"लोकेशन-आधारित ऐप्स के परीक्षण के लिए Android मॉक GPS रूट प्लेयर।","footer.github":"GitHub पर देखें","footer.license":"MIT लाइसेंस","footer.author":"Maxim Popelnitskiy द्वारा","footer.rights":"© 2026 Maxim Popelnitskiy","footer.privacy":"गोपनीयता","footer.cookies":"Cookies","lang_label":"भाषा","privacy.title":"गोपनीयता नीति — Route Spoofer","privacy.desc":"Route Spoofer Android ऐप और इस वेबसाइट की गोपनीयता नीति: कोई खाता नहीं, कोई एनालिटिक्स नहीं, कोई व्यक्तिगत डेटा एकत्र नहीं।","privacy.heading":"गोपनीयता नीति","privacy.intro":"Route Spoofer एक ओपन-सोर्स (MIT) Android ऐप है, जिससे डेवलपर और QA लोकेशन-आधारित ऐप्स का परीक्षण करते समय एक पूर्वनिर्धारित GPS रूट चला सकते हैं। यह नीति ऐप और इस वेबसाइट पर लागू होती है।","privacy.app_heading":"ऐप","privacy.app.0":"कोई खाता नहीं, कोई साइन-अप नहीं।","privacy.app.1":"कोई व्यक्तिगत डेटा एकत्र नहीं करता और किसी सर्वर पर कुछ नहीं भेजता। कोई एनालिटिक्स नहीं, कोई विज्ञापन नहीं, कोई तृतीय-पक्ष ट्रैकिंग SDK नहीं।","privacy.app.2":"स्थान अनुमति केवल आपके डिवाइस पर मॉक GPS स्थान भेजने के लिए उपयोग होती है; आपका स्थान कभी दूरस्थ रूप से संग्रहीत या प्रेषित नहीं किया जाता।","privacy.app.3":"सूचना अनुमति केवल फ़ोरग्राउंड-सेवा की स्थिति सूचना दिखाने के लिए उपयोग होती है।","privacy.app.4":"आपके द्वारा बनाया गया रूट आपके डिवाइस पर स्थानीय रूप से सहेजा जाता है; इसे हटाने के लिए ऐप डेटा साफ़ करें या ऐप अनइंस्टॉल करें।","privacy.web_heading":"यह वेबसाइट","privacy.web.0":"एक स्थैतिक सूचना साइट। कोई साइन-अप नहीं, कोई संपर्क फ़ॉर्म नहीं, कोई व्यक्तिगत डेटा एकत्र नहीं।","privacy.web.1":"आपकी भाषा का चयन आपके ब्राउज़र के localStorage में रखा जाता है ताकि साइट उसे याद रखे; यह आपके डिवाइस पर रहता है और हमें कभी नहीं भेजा जाता।","privacy.web.2":"होस्टिंग प्रदाता सुरक्षा और संचालन के लिए मानक सर्वर अनुरोध लॉग (IP पता, यूज़र एजेंट, टाइमस्टैम्प) रखता है। यह साइट GitHub, Inc. द्वारा होस्ट की गई है।","privacy.closing":"हम डेटा न बेचते हैं और न साझा करते हैं। चूँकि हम कोई व्यक्तिगत डेटा एकत्र नहीं करते, हमारी ओर से एक्सेस, सुधार या मिटाने के लिए कुछ नहीं है; डिवाइस पर मौजूद डेटा पूरी तरह आपके नियंत्रण में है।","privacy.contact_label":"संपर्क:","privacy.contact_link":"GitHub issues","privacy.updated_label":"अंतिम अद्यतन:","privacy.updated":"2026-06-25","cookies.title":"Cookies और लोकल स्टोरेज — Route Spoofer","cookies.desc":"Route Spoofer वेबसाइट का कुकी नोटिस: कोई ट्रैकिंग या विज्ञापन कुकी नहीं; localStorage में केवल एक भाषा फ़ंक्शनल आइटम।","cookies.heading":"Cookies और लोकल स्टोरेज","cookies.body.0":"यह वेबसाइट कोई ट्रैकिंग, एनालिटिक्स या विज्ञापन कुकी, और कोई तृतीय-पक्ष कुकी उपयोग नहीं करती।","cookies.body.1":"यह साइट बिलकुल कोई कुकी सेट नहीं करती।","cookies.body.2":"यह आपके ब्राउज़र के localStorage में एक फ़ंक्शनल आइटम रखती है — आपकी चुनी हुई भाषा («route-spoofer.lang») — ताकि लौटने पर आपकी पसंदीदा भाषा दिखे। यह आपके डिवाइस पर रहती है, हमें नहीं भेजी जाती, और आप इसे ब्राउज़र सेटिंग में कभी भी साफ़ कर सकते हैं।","cookies.body.3":"होस्ट गोपनीयता नीति में बताए अनुसार मानक सर्वर लॉग रखता है। चूँकि कोई ट्रैकिंग तकनीक उपयोग नहीं होती, इसलिए कोई सहमति बैनर नहीं है।","cookies.updated_label":"अंतिम अद्यतन:","cookies.updated":"2026-06-25"}};

/* Route Spoofer landing — client-side language swap + custom language menu.
 *
 * English is already in the DOM. On load we read localStorage["route-spoofer.lang"]
 * (default EN, no browser auto-detect). When another locale is chosen we swap every
 * [data-i18n] element's textContent, [data-i18n-alt] alt and [data-i18n-aria]
 * aria-label from window.I18N, reflect it on <html lang>, the trigger label and the
 * menu's selected state. The header menu is a custom, smooth dropdown — no native
 * <select>, no framework. No page reload. */
(function () {
    'use strict';

    var KEY = 'route-spoofer.lang';
    var I18N = window.I18N || {};
    var root = document.documentElement;
    var DEFAULT = 'en';

    var langEl     = document.getElementById('lang');
    var trigger    = document.getElementById('langTrigger');
    var currentEl  = document.getElementById('langCurrent');

    function options() {
        return Array.prototype.slice.call(document.querySelectorAll('.lang-option'));
    }

    function read() {
        try {
            var l = localStorage.getItem(KEY);
            return (l && I18N[l]) ? l : null;
        } catch (e) { return null; }
    }

    function save(lang) {
        try { localStorage.setItem(KEY, lang); } catch (e) {}
    }

    function apply(lang) {
        var dict = I18N[lang];
        if (!dict) { lang = DEFAULT; dict = I18N[DEFAULT] || {}; }

        document.querySelectorAll('[data-i18n]').forEach(function (el) {
            var v = dict[el.getAttribute('data-i18n')];
            if (v != null) el.textContent = v;
        });
        document.querySelectorAll('[data-i18n-alt]').forEach(function (el) {
            var v = dict[el.getAttribute('data-i18n-alt')];
            if (v != null) el.setAttribute('alt', v);
        });
        document.querySelectorAll('[data-i18n-aria]').forEach(function (el) {
            var v = dict[el.getAttribute('data-i18n-aria')];
            if (v != null) el.setAttribute('aria-label', v);
        });

        root.lang = lang;

        // Reflect on the menu: mark the active option and show its autonym on the
        // trigger (autonyms are the option labels and stay untranslated).
        options().forEach(function (o) {
            var selected = o.getAttribute('data-lang') === lang;
            o.setAttribute('aria-selected', selected ? 'true' : 'false');
            if (selected && currentEl) currentEl.textContent = o.textContent;
        });
    }

    function setLang(lang) {
        if (!I18N[lang]) lang = DEFAULT;
        save(lang);
        apply(lang);
    }

    /* ---- dropdown open/close ---- */
    function isOpen() { return langEl && langEl.classList.contains('open'); }
    function open() {
        if (!langEl) return;
        langEl.classList.add('open');
        if (trigger) trigger.setAttribute('aria-expanded', 'true');
    }
    function close() {
        if (!langEl) return;
        langEl.classList.remove('open');
        if (trigger) trigger.setAttribute('aria-expanded', 'false');
    }

    // Initial render (EN is server-rendered; this syncs lang/menu and swaps text
    // only when a non-EN locale was saved).
    apply(read() || DEFAULT);

    if (trigger) {
        trigger.addEventListener('click', function (e) {
            e.stopPropagation();
            isOpen() ? close() : open();
        });
    }
    options().forEach(function (o) {
        o.addEventListener('click', function () {
            setLang(o.getAttribute('data-lang'));
            close();
        });
    });
    document.addEventListener('click', function (e) {
        if (langEl && !langEl.contains(e.target)) close();
    });
    document.addEventListener('keydown', function (e) {
        if (e.key === 'Escape' || e.key === 'Esc') close();
    });

    window.__rsSetLang = setLang;
})();
